/-- Exponent after identifying the selected observations prescribed by an overlap. -/
def mergedExponent (r s : A → ℕ) (H : OverlapChoice r s) : A → ℕ :=
  fun a => r a + s a - H a

/-- One selected observation has label `s`, while every observation avoids the
forbidden label `r`. -/
def oneSelectedAvoidEvent (i : I) (s r : A) : Set (I → A) :=
  {z | z i = s ∧ ∀ j, z j ≠ r}

/-- Set-valued version used for an entire treatment arm: the selected
observation belongs to `S`, and every observation avoids the disjoint set `R`. -/
def oneSelectedAvoidSetEvent (i : I) (S R : Set A) : Set (I → A) :=
  {z | z i ∈ S ∧ ∀ j, z j ∉ R}

/-- The nonnegative four-cell cone with treatment mass in the overlap band. -/
def overlapCone (epsilon : ℝ) : Set (Cell → ℝ) :=
  {u | (∀ i, 0 ≤ u i) ∧
    epsilon * vectorMass u ≤ vectorArmMass u 1 ∧
    vectorArmMass u 1 ≤ (1 - epsilon) * vectorMass u}

/-- Indicator kernel of one labelled tuple. -/
def patternKernel (g : I → A) (z : I → A) : ℝ :=
  if z = g then 1 else 0

/-- Defines split Count Expression, the stated quantity or construction used in the discrete average-treatment-effect estimator. -/
def splitCountExpression {d : ℕ} (j : Fin 2) (k : Fin d) (ay : Cell) :
    RealArithmeticExpression (HybridCountInput d) := .input (j, k, ay.1, ay.2)

/-- The balanced deterministic half-sample split. -/
def splitIndices (n : ℕ) (j : Fin 2) : Finset (Fin n) :=
  if j = 0 then Finset.univ.filter (fun i => i.1 < n / 2)
  else Finset.univ.filter (fun i => n / 2 ≤ i.1)

/-- The balanced deterministic half-sample split. -/
def splitIndices (n : ℕ) (j : Fin 2) : Finset (Fin n) :=
  if j = 0 then Finset.univ.filter (fun i => i.1 < n / 2)
  else Finset.univ.filter (fun i => n / 2 ≤ i.1)
  -- @realizes I_0,I_1(first floor(n/2) indices and their complement)

def splitSize (n : ℕ) (j : Fin 2) : ℕ := (splitIndices n j).card

/-- Total number of identified observations in an overlap choice. -/
def totalOverlap (r s : A → ℕ) (H : OverlapChoice r s) : ℕ :=
  ∑ a : A, (H a : ℕ)

/-- Two distinct selected observations have prescribed labels while the whole
sample avoids a third, forbidden label. -/
def twoSelectedAvoidEvent (i j : I) (s t r : A) : Set (I → A) :=
  {z | z i = s ∧ z j = t ∧ ∀ l, z l ≠ r}

/-- Two ordered, distinct selected observations belong to `S`, while all
observations avoid the disjoint forbidden set `R`. -/
def twoSelectedAvoidSetEvent (i j : I) (S R : Set A) : Set (I → A) :=
  {z | z i ∈ S ∧ z j ∈ S ∧ ∀ l, z l ∉ R}

/-- Cross-category event: the two selected observations may belong to
different sets, and the full sample avoids a common forbidden set. -/
def twoSelectedAvoidSetsEvent (i j : I) (S T R : Set A) : Set (I → A) :=
  {z | z i ∈ S ∧ z j ∈ T ∧ ∀ l, z l ∉ R}

