/-- Four-cell arm mass. -/
def vectorArmMass (u : Cell → ℝ) (a : Fin 2) : ℝ :=
  u (a, 0) + u (a, 1)

/-- Total four-cell mass. -/
def vectorMass (u : Cell → ℝ) : ℝ :=
  vectorArmMass u 0 + vectorArmMass u 1
